<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Sorting Algorithm Visualizer</title>
<style>
  :root { color-scheme: dark; }
  * { box-sizing: border-box; }
  body {
    margin: 0;
    min-height: 100vh;
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 18px;
    padding: 28px 16px;
    background: #0d1117;
    color: #e6edf3;
    font-family: system-ui, -apple-system, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
  }
  h1 {
    margin: 0;
    font-size: 1.3rem;
    font-weight: 600;
    letter-spacing: .3px;
  }
  .controls { display: flex; gap: 10px; }
  button {
    background: #21262d;
    color: #e6edf3;
    border: 1px solid #3d444d;
    border-radius: 6px;
    padding: 8px 20px;
    font-size: 14px;
    cursor: pointer;
    transition: background .15s;
  }
  button:hover:not(:disabled) { background: #30363d; }
  button:disabled { opacity: .5; cursor: default; }
  #bars {
    display: flex;
    align-items: flex-end;
    gap: 2px;
    width: min(920px, 94vw);
    height: 340px;
    padding: 10px;
    background: #161b22;
    border: 1px solid #30363d;
    border-radius: 10px;
  }
  .bar {
    flex: 1 1 0;
    min-width: 2px;
    background: #4f8cff;
    border-radius: 2px 2px 0 0;
  }
  .bar.compare { background: #ff7b72; }
  .bar.swap    { background: #f2cc60; }
  .bar.sorted  { background: #3fb950; }
</style>
</head>
<body>
  <h1>Sorting Visualizer &mdash; Bubble Sort</h1>
  <div class="controls">
    <button id="sort">Sort</button>
    <button id="shuffle">Shuffle</button>
    <button id="reset">Reset</button>
  </div>
  <div id="bars"></div>

<script>
(function () {
  'use strict';

  var barsEl    = document.getElementById('bars');
  var sortBtn   = document.getElementById('sort');
  var shuffleBtn = document.getElementById('shuffle');
  var resetBtn  = document.getElementById('reset');

  var N = 40;
  var arr = [];
  var initialArr = [];
  var barEls = [];
  var maxVal = 1;

  // Incremental bubble-sort state
  var pass = 0;        // completed passes; last `pass` elements are final
  var idx = 0;         // current comparison index within this pass
  var swapped = false; // any swap during the current pass
  var done = false;

  // Highlight state
  var cmpA = -1, cmpB = -1, swapA = -1, swapB = -1;
  var prevMarked = [];

  var timer = null;

  function isSorted(a) {
    for (var i = 1; i < a.length; i++) if (a[i - 1] > a[i]) return false;
    return true;
  }

  function randomArray(n) {
    var a = [];
    for (var i = 0; i < n; i++) a.push(5 + Math.floor(Math.random() * 96));
    return a;
  }

  function resetState() {
    pass = 0; idx = 0; swapped = false;
    cmpA = cmpB = swapA = swapB = -1;
    prevMarked = [];
    done = isSorted(arr);
  }

  function computeMax() {
    maxVal = 1;
    for (var i = 0; i < arr.length; i++) if (arr[i] > maxVal) maxVal = arr[i];
  }

  function setBarHeight(i) {
    barEls[i].style.height = (arr[i] / maxVal * 100) + '%';
  }

  // Full rebuild of the bar elements from arr.
  function fullRender() {
    barsEl.innerHTML = '';
    barEls = [];
    computeMax();
    for (var i = 0; i < arr.length; i++) {
      var d = document.createElement('div');
      d.className = 'bar' + (done ? ' sorted' : '');
      barsEl.appendChild(d);
      barEls.push(d);
      setBarHeight(i);
    }
  }

  // O(1) visual update after a single sort step.
  function paintStep(passChanged, justDone) {
    var i, d;
    for (i = 0; i < prevMarked.length; i++) {
      d = barEls[prevMarked[i]];
      if (d) d.classList.remove('compare', 'swap');
    }
    prevMarked = [];

    if (justDone) {
      for (i = 0; i < barEls.length; i++) {
        barEls[i].classList.remove('compare', 'swap');
        barEls[i].classList.add('sorted');
      }
      cmpA = cmpB = swapA = swapB = -1;
      return;
    }

    if (passChanged) {
      var s = arr.length - pass; // index that just became final
      if (s >= 0 && s < barEls.length) barEls[s].classList.add('sorted');
    }

    if (swapA >= 0) { setBarHeight(swapA); setBarHeight(swapB); }

    if (cmpA >= 0) { barEls[cmpA].classList.add('compare'); prevMarked.push(cmpA); }
    if (cmpB >= 0) { barEls[cmpB].classList.add('compare'); prevMarked.push(cmpB); }
    if (swapA >= 0) {
      barEls[swapA].classList.remove('compare');
      barEls[swapA].classList.add('swap');
      barEls[swapB].classList.remove('compare');
      barEls[swapB].classList.add('swap');
    }
  }

  // Performs exactly one comparison/step of bubble sort.
  // Returns true once the array is fully sorted, false otherwise.
  function sortStep() {
    var n = arr.length;
    if (n <= 1 || done) {
      done = true;
      paintStep(false, true);
      return true;
    }

    var passChanged = false;
    cmpA = idx; cmpB = idx + 1;
    swapA = swapB = -1;

    if (arr[idx] > arr[idx + 1]) {
      var t = arr[idx]; arr[idx] = arr[idx + 1]; arr[idx + 1] = t;
      swapA = idx; swapB = idx + 1;
      swapped = true;
    }

    idx++;
    if (idx >= n - 1 - pass) {
      idx = 0;
      pass++;
      passChanged = true;
      if (!swapped || pass >= n - 1) done = true;
      swapped = false;
    }

    paintStep(passChanged, done);
    return done;
  }

  function setRunning(running) { sortBtn.disabled = running; }

  function stopAnimation() {
    if (timer !== null) {
      clearInterval(timer);
      timer = null;
    }
    setRunning(false);
  }

  function startAnimation() {
    if (timer !== null || done) return;
    setRunning(true);
    timer = setInterval(function () {
      if (sortStep()) stopAnimation();
    }, 25);
  }

  sortBtn.addEventListener('click', startAnimation);

  shuffleBtn.addEventListener('click', function () {
    stopAnimation();
    arr = randomArray(arr.length || N);
    resetState();
    fullRender();
  });

  resetBtn.addEventListener('click', function () {
    stopAnimation();
    arr = initialArr.slice();
    resetState();
    fullRender();
  });

  // Initial array
  arr = randomArray(N);
  initialArr = arr.slice();
  resetState();
  fullRender();

  // Programmatic API (required for grading)
  window.viz = {
    array: function () { return arr.slice(); },
    setArray: function (a) {
      stopAnimation();
      arr = Array.prototype.map.call(a, Number);
      resetState();
      fullRender();
    },
    sortStep: sortStep,
    sorted: function () { return isSorted(arr); }
  };
})();
</script>
</body>
</html>
